import React from 'react';
import { Link } from 'react-router-dom';

function Navbar({ user, onLogout }) {
  return (
    <nav style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '15px 30px', backgroundColor: '#fff', borderBottom: '1px solid #eee' }}>
      {/* Left - Menu */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '30px' }}>
        <Link to="/" style={{ fontSize: '18px', fontWeight: '500', color: '#333' }}>WOMEN</Link>
        <Link to="/" style={{ fontSize: '18px', fontWeight: '500', color: '#333' }}>MEN</Link>
      </div>

      {/* Center - Logo */}
      <Link to="/" style={{ display: 'flex', alignItems: 'center' }}>
        <img src="/TheRawLogo.svg" alt="Clothing Shop" style={{ height: '50px', width: 'auto' }} />
      </Link>

      {/* Right - User Menu */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
        <Link to="/cart" style={{ fontSize: '16px', color: '#333' }}>🛒 Cart</Link>
        {user ? (
          <>
            <Link to="/profile" style={{ fontSize: '16px', color: '#333' }}>👤</Link>
            <Link to="/orders" style={{ fontSize: '16px', color: '#333' }}>Orders</Link>
            <button onClick={onLogout} style={{ padding: '8px 16px', cursor: 'pointer', background: '#ff6b6b', color: 'white', border: 'none', borderRadius: '4px' }}>Logout</button>
          </>
        ) : (
          <>
            <Link to="/login" style={{ fontSize: '16px', color: '#333' }}>Login</Link>
            <Link to="/register" style={{ fontSize: '16px', color: '#333' }}>Register</Link>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
